/**
 * 雪花飘落特效 - 白天模式
 * 轻量级 Canvas 实现
 */
(function() {
    'use strict';

    var canvas = document.getElementById('snow');
    if (!canvas) return;

    var ctx = canvas.getContext('2d');
    var width, height;
    var flakes = [];
    var FLAKE_COUNT = 80;
    var running = true;
    var animFrame;

    function resize() {
        width = window.innerWidth;
        height = window.innerHeight;
        canvas.width = width;
        canvas.height = height;
    }

    function randomFlake() {
        return {
            x: Math.random() * width,
            y: Math.random() * -height,
            r: Math.random() * 3 + 1,
            speed: Math.random() * 1.2 + 0.4,
            wind: Math.random() * 0.6 - 0.3,
            opacity: Math.random() * 0.5 + 0.5
        };
    }

    function initFlakes() {
        flakes = [];
        for (var i = 0; i < FLAKE_COUNT; i++) {
            var f = randomFlake();
            f.y = Math.random() * height; // spread initially
            flakes.push(f);
        }
    }

    function draw() {
        if (!running) return;

        ctx.clearRect(0, 0, width, height);

        for (var i = 0; i < flakes.length; i++) {
            var f = flakes[i];
            ctx.beginPath();
            ctx.arc(f.x, f.y, f.r, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(255,255,255,' + f.opacity + ')';
            ctx.fill();

            f.y += f.speed;
            f.x += f.wind;

            // 微小摇摆
            f.x += Math.sin(f.y * 0.02) * 0.2;

            if (f.y > height + 5) {
                f.y = -5;
                f.x = Math.random() * width;
            }
            if (f.x > width + 5) f.x = -5;
            if (f.x < -5) f.x = width + 5;
        }

        animFrame = requestAnimationFrame(draw);
    }

    function start() {
        running = true;
        draw();
    }

    function stop() {
        running = false;
        if (animFrame) {
            cancelAnimationFrame(animFrame);
            animFrame = null;
        }
        ctx.clearRect(0, 0, width, height);
    }

    // 暴露控制API
    window.snowControl = {
        start: start,
        stop: stop,
        toggle: function() {
            if (running) { stop(); return false; }
            else { start(); return true; }
        },
        isRunning: function() { return running; }
    };

    resize();
    initFlakes();
    start();

    window.addEventListener('resize', function() {
        resize();
        initFlakes();
    });
})();
